    let curr = stack[stack.length - 1];
    let neighbors = [];
    for (let d of ['n','e','s','w']) {
      let nr = curr.r + DELTA[d].dr;
      let nc = curr.c + DELTA[d].dc;
      if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !visited[nr][nc]) {
